#include<bits/stdc++.h>
using namespace std;
long long b[200010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        double sine,cosi;
        long long lson,rson;
        long long tag;
        node():tag(0){}
    }a[600010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sine=a[a[x].lson].sine+a[a[x].rson].sine;
        a[x].cosi=a[a[x].lson].cosi+a[a[x].rson].cosi;
    }
    void pushadd(long long x,long long val)
    {
        double sina=sin(val),cosa=cos(val),sinb=a[x].sine,cosb=a[x].cosi;
        a[x].sine=sina*cosb+cosa*sinb;
        a[x].cosi=cosa*cosb-sina*sinb;
        a[x].tag+=val;
    }
    void pushdown(long long x)
    {
        if(a[x].tag==0)
        {
            return;
        }
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        pushadd(ls,tg);
        pushadd(rs,tg);
        a[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0;
        if(l==r)
        {
            a[x].sine=sin(b[l]);
            a[x].cosi=cos(b[l]);
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushadd(x,z);
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,z);
        add(a[x].rson,l,r,z);
        pushup(x);
    }
    double getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0.0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sine;
        }
        pushdown(x);
        return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
    }
}t;
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    t.init(1,n);
    long long m;
    scanf("%lld",&m);
    while(m--)
    {
        long long op,l,r,v;
        scanf("%lld%lld%lld",&op,&l,&r);
        if(op==1)
        {
            scanf("%lld",&v);
            t.add(1,l,r,v);
        }
        else
        {
            printf("%.1lf\n",t.getsum(1,l,r));
        }
    }
    return 0;
}
